  2856 | Instruction *InstCombinerImpl::foldICmpSubConstant(ICmpInst &Cmp,
  2857 |                                                    BinaryOperator *Sub,
  2858 |                                                    const APInt &C) {
  2859 |   Value *X = Sub->getOperand(0), *Y = Sub->getOperand(1);
